INSERT INTO TOURS (category_id, name, slug, description, status, price_adult, price_child, images, created_at) VALUES
(1, 'Hà Nội - Hạ Long - Sapa 4N3Đ', 'ha-noi-ha-long-sapa-4n3d', '<!-- SECTION:highlights --><h3>Điểm nổi bật</h3><ul><li>Khám phá Lăng Bác, Chùa Một Cột - biểu tượng thủ đô</li><li>Vịnh Hạ Long - kỳ quan thiên nhiên thế giới</li><li>Sapa mờ sương với ruộng bậc thang tuyệt đẹp</li><li>Thưởng thức ẩm thực đặc sắc miền Bắc</li><li>Hướng dẫn viên nhiệt tình, kinh nghiệm</li></ul><!-- ENDSECTION --><!-- SECTION:itinerary --><h3>Ngày 1: Hà Nội City Tour</h3><ul><li>Sáng: Đón khách tại sân bay Nội Bài, về khách sạn nhận phòng</li><li>Trưa: Ăn trưa tại nhà hàng địa phương</li><li>Chiều: Tham quan Lăng Bác, Chùa Một Cột, Văn Miếu - Quốc Tử Giám</li><li>Tối: Ăn tối, đi dạo quanh Hồ Gươm</li></ul><h3>Ngày 2: Hà Nội - Hạ Long</h3><ul><li>Sáng: Đi Hạ Long, check-in tàu du lịch</li><li>Trưa: Ăn trưa trên tàu</li><li>Chiều: Khám phá hang động Sửng Sốt, chèo thuyền kayak</li><li>Tối: Nghỉ đêm trên tàu</li></ul><h3>Ngày 3: Hạ Long - Sapa</h3><ul><li>Sáng: Tắm biển Titop, trả tàu về bến</li><li>Trưa: Ăn trưa, đi xe về Sapa</li><li>Chiều: Check-in khách sạn Sapa, tham quan bản Cat Cat</li><li>Tối: Ăn tối, nghỉ đêm tại Sapa</li></ul><h3>Ngày 4: Sapa - Hà Nội</h3><ul><li>Sáng: Ngắm bình minh tại Fansipan, tham quan đỉnh núi</li><li>Trưa: Ăn trưa, đi xe về Hà Nội</li><li>Chiều: Mua sắm, đưa khách ra sân bay</li></ul><!-- ENDSECTION --><!-- SECTION:services --><h3>Dịch vụ bao gồm</h3><ul><li>Xe đời mới đưa đón theo lịch trình</li><li>Khách sạn 3-4 sao (2 người/phòng)</li><li>Vé tham quan các điểm du lịch</li><li>Bữa ăn theo chương trình</li><li>Hướng dẫn viên tiếng Việt</li><li>Bảo hiểm du lịch</li><li>Nước uống trên xe</li></ul><!-- ENDSECTION --><!-- SECTION:pricing --><h3>Bảng giá chi tiết</h3><ul><li>Người lớn: 4.500.000đ/người</li><li>Trẻ em (5-11 tuổi): 3.200.000đ/người</li><li>Trẻ em dưới 5 tuổi: Miễn phí (ngủ chung với bố mẹ)</li><li>Phụ thu phòng đơn: 1.500.000đ</li></ul><!-- ENDSECTION -->', 'active', 4500000, 3200000, '["https://images.unsplash.com/photo-1528127269322-539801943592?w=800&q=80","https://images.unsplash.com/photo-1532375810709-75b1da00537c?w=800&q=80"]', '2024-01-10 09:00:00'),
(1, 'Hà Giang - Cao Nguyên Đá Đồng Văn 3N2Đ', 'ha-giang-cao-nguyen-da-3n2d', '<!-- SECTION:highlights --><h3>Điểm nổi bật</h3><ul><li>Chinh phục đèo Mã Pí Lèng - đèo đẹp nhất Việt Nam</li><li>Ngắm hoa tam giác mạch mùa bông nở</li><li>Cột cờ Lũng Cú - điểm cực Bắc của Tổ quốc</li><li>Khám phá văn hóa H''Mông độc đáo</li><li>Check-in tại nhà của vua đá</li></ul><!-- ENDSECTION --><!-- SECTION:itinerary --><h3>Ngày 1: Hà Nội - Hà Giang</h3><ul><li>Sáng: Đón khách, đi xe về Hà Giang</li><li>Trưa: Ăn trưa tại Tuyên Quang</li><li>Chiều: Đến Hà Giang, check-in khách sạn</li><li>Tối: Ăn tối, nghỉ đêm</li></ul><h3>Ngày 2: Hà Giang - Đồng Văn</h3><ul><li>Sáng: Đi qua đèo Mã Pí Lèng, ngắm cảnh</li><li>Trưa: Ăn trưa tại Đồng Văn</li><li>Chiều: Tham quan Cột cờ Lũng Cú, nhà của vua đá</li><li>Tối: Nghỉ đêm tại Đồng Văn</li></ul><h3>Ngày 3: Đồng Văn - Hà Nội</h3><ul><li>Sáng: Mua sắm chợ phiên Đồng Văn, đi xe về</li><li>Trưa: Ăn trưa trên đường</li><li>Chiều: Về đến Hà Nội, kết thúc tour</li></ul><!-- ENDSECTION --><!-- SECTION:services --><h3>Dịch vụ bao gồm</h3><ul><li>Xe đời mới đưa đón</li><li>Khách sạn 2-3 sao</li><li>Bữa ăn theo chương trình</li><li>Hướng dẫn viên địa phương</li><li>Bảo hiểm du lịch</li></ul><!-- ENDSECTION --><!-- SECTION:pricing --><h3>Bảng giá chi tiết</h3><ul><li>Người lớn: 3.800.000đ/người</li><li>Trẻ em (5-11 tuổi): 2.800.000đ/người</li><li>Trẻ em dưới 5 tuổi: Miễn phí</li></ul><!-- ENDSECTION -->', 'active', 3800000, 2800000, '["https://images.unsplash.com/photo-1583417319070-4a69db38a482?w=800&q=80","https://images.unsplash.com/photo-1528127269322-539801943592?w=800&q=80","https://images.unsplash.com/photo-1506905920300-13f10d3d4b3e?w=800&q=80"]', '2024-01-15 10:00:00'),
(2, 'Huế - Đà Nẵng - Hội An 4N3Đ', 'hue-da-nang-hoi-an-4n3d', '<!-- SECTION:highlights --><h3>Điểm nổi bật</h3><ul><li>Tham quan Đại Nội Huế - di sản thế giới</li><li>Biển Mỹ Khê - một trong 6 bãi biển đẹp nhất hành tinh</li><li>Phố cổ Hội An lung linh đèn lồng</li><li>Cầu Rồng - biểu tượng Đà Nẵng</li><li>Thưởng thức đặc sản Cao Lầu, Mì Quảng</li></ul><!-- ENDSECTION --><!-- SECTION:itinerary --><h3>Ngày 1: Đà Nẵng - Huế</h3><ul><li>Sáng: Đón khách tại Đà Nẵng, đi xe về Huế</li><li>Trưa: Ăn trưa tại Huế</li><li>Chiều: Tham quan Đại Nội, lăng tẩm</li><li>Tối: Ăn tối, nghỉ đêm tại Huế</li></ul><h3>Ngày 2: Huế - Đà Nẵng</h3><ul><li>Sáng: Tham quan chùa Thiên Mụ, đi đèo Hải Vân</li><li>Trưa: Ăn trưa tại Đà Nẵng</li><li>Chiều: Tham quan Bà Nà Hills, Cầu Vàng</li><li>Tối: Nghỉ đêm tại Đà Nẵng</li></ul><h3>Ngày 3: Đà Nẵng - Hội An</h3><ul><li>Sáng: Đi biển Mỹ Khê, tham quan Ngũ Hành Sơn</li><li>Trưa: Ăn trưa</li><li>Chiều: Đi Hội An, tham quan phố cổ</li><li>Tối: Ăn tối, ngắm đèn lồng, nghỉ đêm tại Hội An</li></ul><h3>Ngày 4: Hội An - Đà Nẵng</h3><ul><li>Sáng: Mua sắm chợ phiên Hội An, đi xe về Đà Nẵng</li><li>Trưa: Ăn trưa, đưa khách ra sân bay</li></ul><!-- ENDSECTION --><!-- SECTION:services --><h3>Dịch vụ bao gồm</h3><ul><li>Xe đời mới đưa đón</li><li>Khách sạn 3-4 sao</li><li>Vé tham quan Bà Nà Hills</li><li>Bữa ăn theo chương trình</li><li>Hướng dẫn viên tiếng Việt</li><li>Bảo hiểm du lịch</li></ul><!-- ENDSECTION --><!-- SECTION:pricing --><h3>Bảng giá chi tiết</h3><ul><li>Người lớn: 5.200.000đ/người</li><li>Trẻ em (5-11 tuổi): 3.800.000đ/người</li><li>Trẻ em dưới 5 tuổi: Miễn phí</li><li>Phụ thu phòng đơn: 2.000.000đ</li></ul><!-- ENDSECTION -->', 'active', 5200000, 3800000, '["https://images.unsplash.com/photo-1590077428593-a55bb07c4665?w=800&q=80","https://images.unsplash.com/photo-1559592413-7cec4d0cae2b?w=800&q=80"]', '2024-01-20 08:00:00'),
(2, 'Phong Nha - Kẻ Bàng 2N1Đ', 'phong-nha-ke-bang-2n1d', '<!-- SECTION:highlights --><h3>Điểm nổi bật</h3><ul><li>Khám phá Hang Sơn Đoòng - hang động lớn nhất thế giới</li><li>Zipline qua thung lũng sông Chày</li><li>Bơi thuyền kayak trong hang động</li><li>Tham quan động Thiên Đường</li><li>Khám phá hệ sinh thái rừng nhiệt đới</li></ul><!-- ENDSECTION --><!-- SECTION:itinerary --><h3>Ngày 1: Đồng Hới - Phong Nha</h3><ul><li>Sáng: Đón khách tại Đồng Hới, đi Phong Nha</li><li>Trưa: Ăn trưa tại nhà hàng địa phương</li><li>Chiều: Tham quan động Thiên Đường, động Phong Nha</li><li>Tối: Ăn tối, nghỉ đêm tại Phong Nha</li></ul><h3>Ngày 2: Phong Nha - Sông Chày</h3><ul><li>Sáng: Đi sông Chày, zipline, bơi kayak</li><li>Trưa: Ăn trưa picnic</li><li>Chiều: Khám phá hang Tối, trở về Đồng Hới</li><li>Tối: Kết thúc tour</li></ul><!-- ENDSECTION --><!-- SECTION:services --><h3>Dịch vụ bao gồm</h3><ul><li>Xe đưa đón</li><li>Khách sạn 2-3 sao</li><li>Vé tham quan hang động</li><li>Bữa ăn theo chương trình</li><li>Hướng dẫn viên địa phương</li><li>Thiết bị zipline, kayak</li><li>Bảo hiểm du lịch</li></ul><!-- ENDSECTION --><!-- SECTION:pricing --><h3>Bảng giá chi tiết</h3><ul><li>Người lớn: 2.800.000đ/người</li><li>Trẻ em (5-11 tuổi): 2.000.000đ/người</li><li>Trẻ em dưới 5 tuổi: Miễn phí</li></ul><!-- ENDSECTION -->', 'active', 2800000, 2000000, '["https://images.unsplash.com/photo-1583306346313-e9295d87f9eb?w=800&q=80","https://images.unsplash.com/photo-1533050487297-09b450131914?w=800&q=80","https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=800&q=80"]', '2024-02-01 14:00:00'),
(3, 'TP.HCM - Mỹ Tho - Cần Thơ 3N2Đ', 'tphcm-mytho-cantho-3n2d', '<!-- SECTION:highlights --><h3>Điểm nổi bật</h3><ul><li>Trải nghiệm sông nước miệt vườn Tây Nam Bộ</li><li>Tham quan chợ nổi Cái Răng - đặc sản miền Tây</li><li>Khám phá vườn trái cây Mỹ Tho</li><li>Thưởng thức bánh xèo, hủ tiếu miền Tây</li><li>Check-in tại Bến Tre - xứ dừa</li></ul><!-- ENDSECTION --><!-- SECTION:itinerary --><h3>Ngày 1: TP.HCM - Mỹ Tho</h3><ul><li>Sáng: Đón khách, đi xe về Mỹ Tho</li><li>Trưa: Ăn trưa tại vườn trái cây</li><li>Chiều: Tham quan Bến Tre, chèo xuồng ba lá</li><li>Tối: Nghỉ đêm tại Mỹ Tho</li></ul><h3>Ngày 2: Mỹ Tho - Cần Thơ</h3><ul><li>Sáng: Đi Cần Thơ, tham quan chợ nổi Cái Răng</li><li>Trưa: Ăn trưa tại Cần Thơ</li><li>Chiều: Tham quan vườn cẩm thạch, trở về TP.HCM</li><li>Tối: Về đến TP.HCM, kết thúc tour</li></ul><!-- ENDSECTION --><!-- SECTION:services --><h3>Dịch vụ bao gồm</h3><ul><li>Xe đời mới đưa đón</li><li>Khách sạn 2-3 sao</li><li>Vé tham quan</li><li>Bữa ăn theo chương trình</li><li>Hướng dẫn viên tiếng Việt</li><li>Bảo hiểm du lịch</li></ul><!-- ENDSECTION --><!-- SECTION:pricing --><h3>Bảng giá chi tiết</h3><ul><li>Người lớn: 3.500.000đ/người</li><li>Trẻ em (5-11 tuổi): 2.500.000đ/người</li><li>Trẻ em dưới 5 tuổi: Miễn phí</li></ul><!-- ENDSECTION -->', 'active', 3500000, 2500000, '["https://images.unsplash.com/photo-1597165309222-d5c746940c78?w=800&q=80","https://images.unsplash.com/photo-1590077428593-a55bb07c4665?w=800&q=80","https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=800&q=80"]', '2024-02-05 11:00:00'),
(3, 'Phú Quốc - Đảo Ngọc 3N2Đ', 'phu-quoc-dao-ngoc-3n2d', '<!-- SECTION:highlights --><h3>Điểm nổi bật</h3><ul><li>Bãi Sao - bãi biển đẹp nhất Phú Quốc</li><li>Lặn ngắm san hô tại đảo Út</li><li>Câu cá đêm trên biển</li><li>Tham quan nhà tù Phú Quốc</li><li>Thưởng thức hải sản tươi sống</li></ul><!-- ENDSECTION --><!-- SECTION:itinerary --><h3>Ngày 1: TP.HCM - Phú Quốc</h3><ul><li>Sáng: Bay đến Phú Quốc, nhận phòng khách sạn</li><li>Trưa: Ăn trưa, nghỉ ngơi</li><li>Chiều: Tham quan nhà tù Phú Quốc, đi bãi Sao</li><li>Tối: Ăn tối hải sản, nghỉ đêm</li></ul><h3>Ngày 2: Phú Quốc - Đảo Út</h3><ul><li>Sáng: Đi tàu ra đảo Út, lặn ngắm san hô</li><li>Trưa: Ăn trưa trên đảo</li><li>Chiều: Câu cá, bơi biển, trở về đất liền</li><li>Tối: Ăn tối, nghỉ đêm</li></ul><h3>Ngày 3: Phú Quốc - TP.HCM</h3><ul><li>Sáng: Mua sắm đặc sản Phú Quốc, ra sân bay</li><li>Trưa: Bay về TP.HCM</li><li>Chiều: Kết thúc tour</li></ul><!-- ENDSECTION --><!-- SECTION:services --><h3>Dịch vụ bao gồm</h3><ul><li>Vé máy bay khứ hồi</li><li>Khách sạn 3-4 sao</li><li>Vé tham quan</li><li>Bữa ăn theo chương trình</li><li>Hướng dẫn viên địa phương</li><li>Bảo hiểm du lịch</li></ul><!-- ENDSECTION --><!-- SECTION:pricing --><h3>Bảng giá chi tiết</h3><ul><li>Người lớn: 6.800.000đ/người</li><li>Trẻ em (5-11 tuổi): 4.800.000đ/người</li><li>Trẻ em dưới 5 tuổi: Miễn phí</li><li>Phụ thu phòng đơn: 2.500.000đ</li></ul><!-- ENDSECTION -->', 'active', 6800000, 4800000, '["https://images.unsplash.com/photo-1596895111956-bf1cf0599ce5?w=800&q=80","https://images.unsplash.com/photo-1566896022336-7702e477123d?w=800&q=80","https://images.unsplash.com/photo-1544148103-0773bf10d330?w=800&q=80","https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=800&q=80"]', '2024-02-10 09:30:00'),
(4, 'Nha Trang - Vinpearl 4N3Đ', 'nha-trang-vinpearl-4n3d', '<!-- SECTION:highlights --><h3>Điểm nổi bật</h3><ul><li>Vinpearl Land - công viên giải trí lớn nhất miền Trung</li><li>Cáp treo vượt biển dài nhất Việt Nam</li><li>Bãi biển Nha Trang xanh trong</li><li>Thủy cung Vinpearl - aquarium khổng lồ</li><li>Spa và massage thư giãn</li></ul><!-- ENDSECTION --><!-- SECTION:itinerary --><h3>Ngày 1: Nha Trang - Vinpearl</h3><ul><li>Sáng: Đón khách, đi cáp treo ra đảo Vinpearl</li><li>Trưa: Ăn trưa tại resort</li><li>Chiều: Tham quan Vinpearl Land, thủy cung</li><li>Tối: Nghỉ đêm tại resort Vinpearl</li></ul><h3>Ngày 2: Vinpearl - Nha Trang</h3><ul><li>Sáng: Bơi biển, tham quan vườn hoa</li><li>Trưa: Ăn trưa</li><li>Chiều: Spa, massage, trở về đất liền</li><li>Tối: Ăn tối, nghỉ đêm tại Nha Trang</li></ul><h3>Ngày 3: Nha Trang City Tour</h3><ul><li>Sáng: Tham quan Viện Hải dương học, chợ Đầm</li><li>Trưa: Ăn trưa</li><li>Chiều: Đi bãi biển, nghỉ ngơi</li><li>Tối: Ăn tối, nghỉ đêm</li></ul><h3>Ngày 4: Nha Trang</h3><ul><li>Sáng: Mua sắm đặc sản, ra sân bay</li><li>Trưa: Kết thúc tour</li></ul><!-- ENDSECTION --><!-- SECTION:services --><h3>Dịch vụ bao gồm</h3><ul><li>Vé cáp treo khứ hồi</li><li>Resort 4-5 sao</li><li>Vé Vinpearl Land</li><li>Bữa ăn theo chương trình</li><li>Hướng dẫn viên</li><li>Bảo hiểm du lịch</li></ul><!-- ENDSECTION --><!-- SECTION:pricing --><h3>Bảng giá chi tiết</h3><ul><li>Người lớn: 5.800.000đ/người</li><li>Trẻ em (5-11 tuổi): 4.200.000đ/người</li><li>Trẻ em dưới 5 tuổi: Miễn phí</li><li>Phụ thu phòng đơn: 3.000.000đ</li></ul><!-- ENDSECTION -->', 'active', 5800000, 4200000, '["https://images.unsplash.com/photo-1566896022336-7702e477123d?w=800&q=80","https://images.unsplash.com/photo-1596895111956-bf1cf0599ce5?w=800&q=80","https://images.unsplash.com/photo-1544148103-0773bf10d330?w=800&q=80"]', '2024-02-15 10:00:00'),
(4, 'Đà Nẵng - Bà Nà Hills 3N2Đ', 'da-nang-ba-na-hills-3n2d', '<!-- SECTION:highlights --><h3>Điểm nổi bật</h3><ul><li>Cầu Vàng - biểu tượng mới của Đà Nẵng</li><li>Làng Pháp trên đỉnh núi Bà Nà</li><li>Cáp treo dài nhất thế giới</li><li>Tham quan Ngũ Hành Sơn</li><li>Check-in tại biển Mỹ Khê</li></ul><!-- ENDSECTION --><!-- SECTION:itinerary --><h3>Ngày 1: Đà Nẵng - Bà Nà</h3><ul><li>Sáng: Đón khách, đi Bà Nà Hills</li><li>Trưa: Ăn trưa tại Bà Nà</li><li>Chiều: Tham quan Làng Pháp, Cầu Vàng</li><li>Tối: Nghỉ đêm tại Đà Nẵng</li></ul><h3>Ngày 2: Đà Nẵng City Tour</h3><ul><li>Sáng: Đi biển Mỹ Khê, tham quan Ngũ Hành Sơn</li><li>Trưa: Ăn trưa</li><li>Chiều: Tham quan Cầu Rồng, chợ Hàn</li><li>Tối: Ăn tối, nghỉ đêm</li></ul><h3>Ngày 3: Đà Nẵng</h3><ul><li>Sáng: Mua sắm đặc sản, ra sân bay</li><li>Trưa: Kết thúc tour</li></ul><!-- ENDSECTION --><!-- SECTION:services --><h3>Dịch vụ bao gồm</h3><ul><li>Vé cáp treo Bà Nà Hills</li><li>Khách sạn 3-4 sao</li><li>Vé tham quan Ngũ Hành Sơn</li><li>Bữa ăn theo chương trình</li><li>Hướng dẫn viên</li><li>Bảo hiểm du lịch</li></ul><!-- ENDSECTION --><!-- SECTION:pricing --><h3>Bảng giá chi tiết</h3><ul><li>Người lớn: 4.200.000đ/người</li><li>Trẻ em (5-11 tuổi): 3.000.000đ/người</li><li>Trẻ em dưới 5 tuổi: Miễn phí</li></ul><!-- ENDSECTION -->', 'active', 4200000, 3000000, '["https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=800&q=80","https://images.unsplash.com/photo-1559592413-7cec4d0cae2b?w=800&q=80","https://images.unsplash.com/photo-1590077428593-a55bb07c4665?w=800&q=80"]', '2024-02-20 08:00:00'),
(5, 'Sapa - Fansipan 2N1Đ', 'sapa-fansipan-2n1d', '<!-- SECTION:highlights --><h3>Điểm nổi bật</h3><ul><li>Chinh phục đỉnh Fansipan - nóc nhà Đông Dương</li><li>Tàu hỏa leo núi trải nghiệm độc đáo</li><li>Ruộng bậc thang Mường Hoa</li><li>Khám phá văn hóa người Dao đỏ</li><li>Thưởng thức thịt trâu gác bếp</li></ul><!-- ENDSECTION --><!-- SECTION:itinerary --><h3>Ngày 1: Hà Nội - Sapa</h3><ul><li>Sáng: Đón khách, đi tàu hỏa về Sapa</li><li>Trưa: Ăn trưa trên tàu</li><li>Chiều: Đến Sapa, check-in khách sạn</li><li>Tối: Ăn tối, nghỉ đêm</li></ul><h3>Ngày 2: Sapa - Fansipan</h3><ul><li>Sáng: Đi cáp treo lên Fansipan</li><li>Trưa: Ăn trưa trên đỉnh núi</li><li>Chiều: Tham quan bản Mường Hoa, trở về Sapa</li><li>Tối: Đi tàu về Hà Nội</li></ul><!-- ENDSECTION --><!-- SECTION:services --><h3>Dịch vụ bao gồm</h3><ul><li>Vé tàu hỏa khứ hồi</li><li>Vé cáp treo Fansipan</li><li>Khách sạn 2-3 sao</li><li>Bữa ăn theo chương trình</li><li>Hướng dẫn viên địa phương</li><li>Bảo hiểm du lịch</li></ul><!-- ENDSECTION --><!-- SECTION:pricing --><h3>Bảng giá chi tiết</h3><ul><li>Người lớn: 3.200.000đ/người</li><li>Trẻ em (5-11 tuổi): 2.400.000đ/người</li><li>Trẻ em dưới 5 tuổi: Miễn phí</li></ul><!-- ENDSECTION -->', 'active', 3200000, 2400000, '["https://images.unsplash.com/photo-1548266652-99cf27701ced?w=800&q=80","https://images.unsplash.com/photo-1532375810709-75b1da00537c?w=800&q=80","https://images.unsplash.com/photo-1506905920300-13f10d3d4b3e?w=800&q=80"]', '2024-03-01 09:00:00'),
(6, 'Hà Nội - Ninh Bình - Bái Đính - Tràng An', 'ha-noi-ninh-binh-trang-an', '<!-- SECTION:highlights --><h3>Điểm nổi bật</h3><ul><li>Chùa Bái Đính - chùa lớn nhất Đông Nam Á</li><li>Tràng An - di sản thế giới kép</li><li>Động Tam Cốc - Vịnh Hạ Long trên cạn</li><li>Tham quan đền vua Đinh Tiên Hoàng</li><li>Chèo thuyền tam bản</li></ul><!-- ENDSECTION --><!-- SECTION:itinerary --><h3>Ngày 1: Hà Nội - Ninh Bình</h3><ul><li>Sáng: Đón khách, đi xe về Ninh Bình</li><li>Trưa: Ăn trưa</li><li>Chiều: Tham quan chùa Bái Đính</li><li>Tối: Ăn tối, nghỉ đêm tại Ninh Bình</li></ul><h3>Ngày 2: Ninh Bình - Hà Nội</h3><ul><li>Sáng: Đi Tràng An, chèo thuyền</li><li>Trưa: Ăn trưa</li><li>Chiều: Tham quan động Tam Cốc, trở về Hà Nội</li><li>Tối: Kết thúc tour</li></ul><!-- ENDSECTION --><!-- SECTION:services --><h3>Dịch vụ bao gồm</h3><ul><li>Xe đời mới đưa đón</li><li>Khách sạn 2-3 sao</li><li>Vé tham quan</li><li>Bữa ăn theo chương trình</li><li>Hướng dẫn viên</li><li>Bảo hiểm du lịch</li></ul><!-- ENDSECTION --><!-- SECTION:pricing --><h3>Bảng giá chi tiết</h3><ul><li>Người lớn: 1.800.000đ/người</li><li>Trẻ em (5-11 tuổi): 1.300.000đ/người</li><li>Trẻ em dưới 5 tuổi: Miễn phí</li></ul><!-- ENDSECTION -->', 'active', 1800000, 1300000, '["https://images.unsplash.com/photo-1586495981346-94c06fb90f91?w=800&q=80","https://images.unsplash.com/photo-1528127269322-539801943592?w=800&q=80","https://images.unsplash.com/photo-1583417319070-4a69db38a482?w=800&q=80"]', '2024-03-05 14:00:00'),
(7, 'Hội An - Tour Ẩm Thực Đêm', 'hoi-an-am-thuc-dem', '<!-- SECTION:highlights --><h3>Điểm nổi bật</h3><ul><li>Khám phá ẩm thực đường phố Hội An</li><li>Thưởng thức bánh mì Phượng, cao lầu</li><li>Ngắm đèn lồng lung linh phố cổ</li><li>Tham quan các quán ăn cổ</li><li>Học làm bánh xèo, bánh đúc</li></ul><!-- ENDSECTION --><!-- SECTION:itinerary --><h3>Ngày 1: Đà Nẵng - Hội An</h3><ul><li>Sáng: Đón khách, đi Hội An</li><li>Trưa: Ăn trưa đặc sản Hội An</li><li>Chiều: Tham quan phố cổ, thưởng thức bánh mì Phượng</li><li>Tối: Ăn tối ẩm thực, ngắm đèn lồng</li></ul><!-- ENDSECTION --><!-- SECTION:services --><h3>Dịch vụ bao gồm</h3><ul><li>Xe đưa đón</li><li>Bữa ăn theo chương trình</li><li>Hướng dẫn viên ẩm thực</li><li>Bảo hiểm du lịch</li></ul><!-- ENDSECTION --><!-- SECTION:pricing --><h3>Bảng giá chi tiết</h3><ul><li>Người lớn: 850.000đ/người</li><li>Trẻ em (5-11 tuổi): 600.000đ/người</li><li>Trẻ em dưới 5 tuổi: Miễn phí</li></ul><!-- ENDSECTION -->', 'active', 850000, 600000, '["https://images.unsplash.com/photo-1504214208698-ea1916a2195a?w=800&q=80","https://images.unsplash.com/photo-1559592413-7cec4d0cae2b?w=800&q=80","https://images.unsplash.com/photo-1590077428593-a55bb07c4665?w=800&q=80"]', '2024-03-10 11:00:00'),
(8, 'Đà Lạt - Thành Phố Ngàn Hoa 4N3Đ', 'da-lat-thanh-pho-ngan-hoa', '<!-- SECTION:highlights --><h3>Điểm nổi bật</h3><ul><li>Thành phố ngàn hoa với vườn hoa tuyệt đẹp</li><li>Khám phá thung lũng Tình Yêu</li><li>Tham quan Dinh Bảo Đại</li><li>Chinh phục đèo Pongour</li><li>Thưởng thức dâu tây Đà Lạt</li></ul><!-- ENDSECTION --><!-- SECTION:itinerary --><h3>Ngày 1: TP.HCM - Đà Lạt</h3><ul><li>Sáng: Bay đến Đà Lạt, nhận phòng</li><li>Trưa: Ăn trưa</li><li>Chiều: Tham quan thung lũng Tình Yêu</li><li>Tối: Ăn tối, nghỉ đêm</li></ul><h3>Ngày 2: Đà Lạt City Tour</h3><ul><li>Sáng: Tham quan Dinh Bảo Đại, vườn hoa</li><li>Trưa: Ăn trưa</li><li>Chiều: Đi chợ Đà Lạt, mua sắm</li><li>Tối: Ăn tối, nghỉ đêm</li></ul><h3>Ngày 3: Đà Lạt - Đèo Pongour</h3><ul><li>Sáng: Đi đèo Pongour, thác Datanla</li><li>Trưa: Ăn trưa picnic</li><li>Chiều: Trở về Đà Lạt, nghỉ ngơi</li><li>Tối: Ăn tối, nghỉ đêm</li></ul><h3>Ngày 4: Đà Lạt - TP.HCM</h3><ul><li>Sáng: Mua sắm đặc sản, ra sân bay</li><li>Trưa: Bay về TP.HCM</li></ul><!-- ENDSECTION --><!-- SECTION:services --><h3>Dịch vụ bao gồm</h3><ul><li>Vé máy bay khứ hồi</li><li>Resort 3-4 sao</li><li>Vé tham quan</li><li>Bữa ăn theo chương trình</li><li>Hướng dẫn viên</li><li>Bảo hiểm du lịch</li></ul><!-- ENDSECTION --><!-- SECTION:pricing --><h3>Bảng giá chi tiết</h3><ul><li>Người lớn: 4.800.000đ/người</li><li>Trẻ em (5-11 tuổi): 3.500.000đ/người</li><li>Trẻ em dưới 5 tuổi: Miễn phí</li><li>Phụ thu phòng đơn: 2.000.000đ</li></ul><!-- ENDSECTION -->', 'active', 4800000, 3500000, '["https://images.unsplash.com/photo-1584172459597-619bb936a093?w=800&q=80","https://images.unsplash.com/photo-1586495981346-94c06fb90f91?w=800&q=80","https://images.unsplash.com/photo-1506905920300-13f10d3d4b3e?w=800&q=80"]', '2024-03-15 08:30:00'),
(9, 'Mộc Châu - Trekking Hang Táu 2N1Đ', 'moc-chau-trekking-hang-tau', '<!-- SECTION:highlights --><h3>Điểm nổi bật</h3><ul><li>Trekking tại hang Táu hoang sơ</li><li>Cắm trại giữa thiên nhiên</li><li>Khám phá văn hóa người Thái</li><li>Thưởng thức chè Mộc Châu</li><li>Check-in tại đồi chè</li></ul><!-- ENDSECTION --><!-- SECTION:itinerary --><h3>Ngày 1: Hà Nội - Mộc Châu</h3><ul><li>Sáng: Đón khách, đi xe về Mộc Châu</li><li>Trưa: Ăn trưa</li><li>Chiều: Trekking đến hang Táu, cắm trại</li><li>Tối: Ăn tối BBQ, ngủ lều</li></ul><h3>Ngày 2: Mộc Châu - Hà Nội</h3><ul><li>Sáng: Tham quan đồi chè, trở về</li><li>Trưa: Ăn trưa</li><li>Chiều: Về đến Hà Nội</li></ul><!-- ENDSECTION --><!-- SECTION:services --><h3>Dịch vụ bao gồm</h3><ul><li>Xe đưa đón</li><li>Lều trại, thiết bị cắm trại</li><li>Bữa ăn theo chương trình</li><li>Hướng dẫn viên trekking</li><li>Bảo hiểm du lịch</li></ul><!-- ENDSECTION --><!-- SECTION:pricing --><h3>Bảng giá chi tiết</h3><ul><li>Người lớn: 2.200.000đ/người</li><li>Trẻ em (5-11 tuổi): 1.600.000đ/người</li><li>Trẻ em dưới 5 tuổi: Miễn phí</li></ul><!-- ENDSECTION -->', 'active', 2200000, 1600000, '["https://images.unsplash.com/photo-1506905920300-13f10d3d4b3e?w=800&q=80","https://images.unsplash.com/photo-1583417319070-4a69db38a482?w=800&q=80","https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=800&q=80"]', '2024-03-20 13:00:00'),
(10, 'Phan Thiết - Mũi Né Resort 3N2Đ', 'phan-thiet-mui-ne-resort', '<!-- SECTION:highlights --><h3>Điểm nổi bật</h3><ul><li>Resort 4 sao với hồ bơi riêng</li><li>Bãi biển Mũi Né đẹp</li><li>Tham quan đồi cát</li><li>Thưởng thức hải sản tươi</li><li>Nghỉ dưỡng cho gia đình</li></ul><!-- ENDSECTION --><!-- SECTION:itinerary --><h3>Ngày 1: TP.HCM - Phan Thiết</h3><ul><li>Sáng: Đón khách, đi xe về Phan Thiết</li><li>Trưa: Ăn trưa</li><li>Chiều: Check-in resort, nghỉ ngơi</li><li>Tối: Ăn tối, nghỉ đêm</li></ul><h3>Ngày 2: Mũi Né</h3><ul><li>Sáng: Đi biển, tham quan đồi cát</li><li>Trưa: Ăn trưa</li><li>Chiều: Nghỉ ngơi tại resort</li><li>Tối: Ăn tối, nghỉ đêm</li></ul><h3>Ngày 3: Phan Thiết - TP.HCM</h3><ul><li>Sáng: Mua sắm đặc sản, trở về</li><li>Trưa: Ăn trưa</li><li>Chiều: Về đến TP.HCM</li></ul><!-- ENDSECTION --><!-- SECTION:services --><h3>Dịch vụ bao gồm</h3><ul><li>Resort 4 sao</li><li>Bữa ăn theo chương trình</li><li>Hướng dẫn viên</li><li>Bảo hiểm du lịch</li></ul><!-- ENDSECTION --><!-- SECTION:pricing --><h3>Bảng giá chi tiết</h3><ul><li>Người lớn: 4.200.000đ/người</li><li>Trẻ em (5-11 tuổi): 3.000.000đ/người</li><li>Trẻ em dưới 5 tuổi: Miễn phí</li><li>Phụ thu phòng đơn: 2.000.000đ</li></ul><!-- ENDSECTION -->', 'active', 4200000, 3000000, '["https://images.unsplash.com/photo-1559827260-dc66d52bef19?w=800&q=80","https://images.unsplash.com/photo-1566896022336-7702e477123d?w=800&q=80","https://images.unsplash.com/photo-1520250497591-112f2f40a3f4?w=800&q=80"]', '2024-03-25 10:00:00'),
(11, 'Nha Trang - Tour Trăng Mật 4N3Đ', 'nha-trang-trang-mat-4n3d', '<!-- SECTION:highlights --><h3>Điểm nổi bật</h3><ul><li>Romantic package cho cặp đôi</li><li>Bữa tối bãi biển lãng mạn</li><li>Spa trị liệu cho 2 người</li><li>Resort view biển đẹp</li><li>Hoa và nến trang trí phòng</li></ul><!-- ENDSECTION --><!-- SECTION:itinerary --><h3>Ngày 1: TP.HCM - Nha Trang</h3><ul><li>Sáng: Bay đến Nha Trang, nhận phòng</li><li>Trưa: Ăn trưa</li><li>Chiều: Spa, massage</li><li>Tối: Bữa tối lãng mạn, nghỉ đêm</li></ul><h3>Ngày 2: Nha Trang</h3><ul><li>Sáng: Bơi biển, tham quan</li><li>Trưa: Ăn trưa</li><li>Chiều: Spa, nghỉ ngơi</li><li>Tối: Ăn tối, nghỉ đêm</li></ul><h3>Ngày 3: Nha Trang</h3><ul><li>Sáng: Tour đảo, lặn ngắm</li><li>Trưa: Ăn trưa trên đảo</li><li>Chiều: Trở về, nghỉ ngơi</li><li>Tối: Bữa tối lãng mạn, nghỉ đêm</li></ul><h3>Ngày 4: Nha Trang - TP.HCM</h3><ul><li>Sáng: Mua sắm, ra sân bay</li><li>Trưa: Bay về TP.HCM</li></ul><!-- ENDSECTION --><!-- SECTION:services --><h3>Dịch vụ bao gồm</h3><ul><li>Vé máy bay khứ hồi</li><li>Resort 5 sao (1 phòng cho 2 người)</li><li>Bữa ăn theo chương trình</li><li>Spa trị liệu</li><li>Hoa và nến trang trí</li><li>Bảo hiểm du lịch</li></ul><!-- ENDSECTION --><!-- SECTION:pricing --><h3>Bảng giá chi tiết</h3><ul><li>Cặp đôi: 8.500.000đ/2 người</li><li>Không nhận trẻ em</li></ul><!-- ENDSECTION -->', 'active', 8500000, 0, '["https://images.unsplash.com/photo-1544148103-0773bf10d330?w=800&q=80","https://images.unsplash.com/photo-1548266652-99cf27701ced?w=800&q=80","https://images.unsplash.com/photo-1596895111956-bf1cf0599ce5?w=800&q=80"]', '2024-04-01 09:00:00'),
(12, 'Vũng Tàu - Team Building 2N1Đ', 'vung-tau-team-building', '<!-- SECTION:highlights --><h3>Điểm nổi bật</h3><ul><li>Chương trình team building chuyên nghiệp</li><li>Games bãi biển sôi động</li><li>Gala dinner đêm thứ 2</li><li>Tham quan tượng Chúa Kitô</li><li>Check-in tại Bãi Trước</li></ul><!-- ENDSECTION --><!-- SECTION:itinerary --><h3>Ngày 1: TP.HCM - Vũng Tàu</h3><ul><li>Sáng: Đón khách, đi xe về Vũng Tàu</li><li>Trưa: Ăn trưa</li><li>Chiều: Team building games bãi biển</li><li>Tối: Gala dinner, nghỉ đêm</li></ul><h3>Ngày 2: Vũng Tàu - TP.HCM</h3><ul><li>Sáng: Tham quan tượng Chúa Kitô</li><li>Trưa: Ăn trưa</li><li>Chiều: Trở về TP.HCM</li></ul><!-- ENDSECTION --><!-- SECTION:services --><h3>Dịch vụ bao gồm</h3><ul><li>Xe đưa đón</li><li>Khách sạn 3-4 sao</li><li>Team building chuyên nghiệp</li><li>Bữa ăn theo chương trình</li><li>Gala dinner</li><li>Bảo hiểm du lịch</li></ul><!-- ENDSECTION --><!-- SECTION:pricing --><h3>Bảng giá chi tiết</h3><ul><li>Người lớn: 1.500.000đ/người</li><li>Trẻ em (5-11 tuổi): 1.000.000đ/người</li><li>Trẻ em dưới 5 tuổi: Miễn phí</li></ul><!-- ENDSECTION -->', 'active', 1500000, 1000000, '["https://images.unsplash.com/photo-1520250497591-112f2f40a3f4?w=800&q=80","https://images.unsplash.com/photo-1566896022336-7702e477123d?w=800&q=80","https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=800&q=80"]', '2024-04-05 15:00:00'),
(4, 'Quy Nhơn - Eo Gió 3N2Đ', 'quy-nhon-eo-gio-3n2d', '<!-- SECTION:highlights --><h3>Điểm nổi bật</h3><ul><li>Kỳ Co - bãi biển đẹp nhất Quy Nhơn</li><li>Eo Gió - Maldives của Việt Nam</li><li>Tháp Đôi Quy Nhơn</li><li>Thưởng thức đặc sản bún chả cá</li><li>Check-in tại Hầm Hô</li></ul><!-- ENDSECTION --><!-- SECTION:itinerary --><h3>Ngày 1: TP.HCM - Quy Nhơn</h3><ul><li>Sáng: Bay đến Quy Nhơn, nhận phòng</li><li>Trưa: Ăn trưa</li><li>Chiều: Đi Eo Gió, Kỳ Co</li><li>Tối: Ăn tối, nghỉ đêm</li></ul><h3>Ngày 2: Quy Nhơn City Tour</h3><ul><li>Sáng: Tham quan Tháp Đôi, chợ Quy Nhơn</li><li>Trưa: Ăn trưa đặc sản</li><li>Chiều: Đi Hầm Hô, bãi biển</li><li>Tối: Ăn tối, nghỉ đêm</li></ul><h3>Ngày 3: Quy Nhơn - TP.HCM</h3><ul><li>Sáng: Mua sắm đặc sản, ra sân bay</li><li>Trưa: Bay về TP.HCM</li></ul><!-- ENDSECTION --><!-- SECTION:services --><h3>Dịch vụ bao gồm</h3><ul><li>Vé máy bay khứ hồi</li><li>Khách sạn 3-4 sao</li><li>Vé tham quan</li><li>Bữa ăn theo chương trình</li><li>Hướng dẫn viên</li><li>Bảo hiểm du lịch</li></ul><!-- ENDSECTION --><!-- SECTION:pricing --><h3>Bảng giá chi tiết</h3><ul><li>Người lớn: 3.900.000đ/người</li><li>Trẻ em (5-11 tuổi): 2.800.000đ/người</li><li>Trẻ em dưới 5 tuổi: Miễn phí</li><li>Phụ thu phòng đơn: 1.500.000đ</li></ul><!-- ENDSECTION -->', 'active', 3900000, 2800000, '["https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=800&q=80","https://images.unsplash.com/photo-1596895111956-bf1cf0599ce5?w=800&q=80","https://images.unsplash.com/photo-1544148103-0773bf10d330?w=800&q=80","https://images.unsplash.com/photo-1566896022336-7702e477123d?w=800&q=80"]', '2024-04-10 11:00:00'),
(2, 'Quảng Bình - Sông Chày - Hang Tối', 'quang-binh-song-chay-hang-toi', '<!-- SECTION:highlights --><h3>Điểm nổi bật</h3><ul><li>Zipline qua thung lũng sông Chày</li><li>Bơi thuyền kayak trong hang động</li><li>Khám phá Hang Tối hoang sơ</li><li>Tham quan động Phong Nha</li><li>Trải nghiệm thiên nhiên hoang dã</li></ul><!-- ENDSECTION --><!-- SECTION:itinerary --><h3>Ngày 1: Đồng Hới - Phong Nha</h3><ul><li>Sáng: Đón khách, đi Phong Nha</li><li>Trưa: Ăn trưa</li><li>Chiều: Tham quan động Phong Nha</li><li>Tối: Ăn tối, nghỉ đêm</li></ul><h3>Ngày 2: Phong Nha - Sông Chày</h3><ul><li>Sáng: Đi sông Chày, zipline</li><li>Trưa: Ăn trưa picnic</li><li>Chiều: Bơi kayak, khám phá Hang Tối</li><li>Tối: Trở về Đồng Hới</li></ul><!-- ENDSECTION --><!-- SECTION:services --><h3>Dịch vụ bao gồm</h3><ul><li>Xe đưa đón</li><li>Khách sạn 2-3 sao</li><li>Vé tham quan</li><li>Thiết bị zipline, kayak</li><li>Bữa ăn theo chương trình</li><li>Hướng dẫn viên</li><li>Bảo hiểm du lịch</li></ul><!-- ENDSECTION --><!-- SECTION:pricing --><h3>Bảng giá chi tiết</h3><ul><li>Người lớn: 2.500.000đ/người</li><li>Trẻ em (5-11 tuổi): 1.800.000đ/người</li><li>Trẻ em dưới 5 tuổi: Miễn phí</li></ul><!-- ENDSECTION -->', 'active', 2500000, 1800000, '["https://images.unsplash.com/photo-1533050487297-09b450131914?w=800&q=80","https://images.unsplash.com/photo-1583306346313-e9295d87f9eb?w=800&q=80","https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=800&q=80"]', '2024-04-15 14:00:00');
